import { Component, HostListener } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { VerificationService } from './verification.service';
import { AuthService } from './auth.service';
import { LoginComponent } from './login/login.component';
import { CatalogueComponent } from './catalogue/catalogue.component';
import { NotaryDashboardComponent } from './notary-dashboard/notary-dashboard.component';
import { TitlingTrackerComponent } from './titling-tracker/titling-tracker.component';
import { PreInvestDashboardComponent } from './pre-invest-dashboard/pre-invest-dashboard.component';
import { InvestmentMarketplaceComponent } from './investment-marketplace/investment-marketplace.component';
import { SubscriptionComponent } from './subscription/subscription.component';
import { InvestorDashboardComponent } from './investor-dashboard/investor-dashboard.component';
import { AdminDashboardComponent } from './admin-dashboard/admin-dashboard.component';

@Component({
  selector: 'app-root',
  standalone: true,
  imports: [CommonModule, FormsModule, LoginComponent, CatalogueComponent, NotaryDashboardComponent, TitlingTrackerComponent, PreInvestDashboardComponent, InvestmentMarketplaceComponent, SubscriptionComponent, InvestorDashboardComponent, AdminDashboardComponent],
  templateUrl: './app.component.html',
  styleUrls: ['./app.component.css']
})
export class AppComponent {
  titleNumber: string = '';
  isChecking: boolean = false;
  verificationResult: any = null;
  errorMessage: string = '';

  // PWA Install Prompt
  deferredPrompt: any;
  showInstallButton: boolean = false;

  // Navigation state
  currentView: 'VERIFY' | 'CATALOGUE' | 'NOTARY' | 'TITRE' | 'PREINVEST' | 'COINVEST' | 'CLUB' | 'PORTFOLIO' | 'ADMIN' = 'VERIFY';
  
  // Auth state
  showLogin: boolean = false;
  isLoggedIn: boolean = false;
  userRole: string = 'BUYER'; // Added userRole

  constructor(
    private verificationService: VerificationService,
    public authService: AuthService
  ) {
    this.isLoggedIn = this.authService.isLoggedIn();
  }

  onLoginSuccess() {
    this.showLogin = false;
    this.isLoggedIn = true;
    // Mock setting role for prototype (e.g. if phone contains '777', set as NOTARY)
    this.userRole = 'NOTARY'; // Defaulting for demo
  }

  logout() {
    this.authService.logout();
    this.isLoggedIn = false;
  }

  downloadPdf() {
    if (!this.verificationResult || !this.verificationResult.id) return;
    
    this.verificationService.downloadReport(this.verificationResult.id).subscribe({
      next: (blob) => {
        const url = window.URL.createObjectURL(blob);
        const link = document.createElement('a');
        link.href = url;
        link.download = `Rapport_maTerre_${this.verificationResult.title}.pdf`;
        link.click();
        window.URL.revokeObjectURL(url);
      },
      error: (err) => console.error('Download error:', err)
    });
  }

  @HostListener('window:beforeinstallprompt', ['$event'])
  onBeforeInstallPrompt(e: any) {
    // Prevent Chrome 67 and earlier from automatically showing the prompt
    e.preventDefault();
    // Stash the event so it can be triggered later.
    this.deferredPrompt = e;
    this.showInstallButton = true;
  }

  installPwa() {
    if (!this.deferredPrompt) return;
    this.showInstallButton = false;
    this.deferredPrompt.prompt();
    this.deferredPrompt.userChoice.then((choiceResult: any) => {
      if (choiceResult.outcome === 'accepted') {
        console.log('User accepted the install prompt');
      }
      this.deferredPrompt = null;
    });
  }

  checkTitle() {
    if (!this.titleNumber) return;
    
    this.isChecking = true;
    this.verificationResult = null;
    this.errorMessage = '';

    // Step 1: Submit Request to the Backend
    this.verificationService.submitRequest(this.titleNumber).subscribe({
      next: (request) => {
        // Step 2: Check for existing property status (Instant Arbitration)
        this.verificationService.getPropertyStatus(this.titleNumber).subscribe({
          next: (property) => {
            this.isChecking = false;
            this.verificationResult = {
              title: property.titleNumber,
              status: property.currentStatus,
              message: this.getVerdictMessage(property.currentStatus),
              date: new Date().toLocaleDateString()
            };
          },
          error: () => {
            // Case where property is not yet in DB, but request is submitted for 48h check
            this.isChecking = false;
            this.verificationResult = {
              title: this.titleNumber,
              status: 'PENDING',
              message: 'Vérification en cours. Votre rapport sera disponible sous 48h.',
              date: new Date().toLocaleDateString()
            };
          }
        });
      },
      error: (err) => {
        this.isChecking = false;
        this.errorMessage = 'Erreur lors de la soumission. Veuillez réessayer.';
        console.error('API Error:', err);
      }
    });
  }

  private getVerdictMessage(status: string): string {
    switch (status) {
      case 'GREEN': return 'Titre foncier audité. Aucune charge détectée.';
      case 'RED': return 'ATTENTION : Litige foncier détecté sur ce titre.';
      case 'YELLOW': return 'PRUDENCE : Charges ou prénotations identifiées.';
      default: return 'Statut inconnu. Un arbitrage approfondi est nécessaire.';
    }
  }
}
<div class="app-container">
  <header style="background: var(--mt-green); color: white; padding: 1rem; display: flex; align-items: center; justify-content: space-between;">
    <div style="display: flex; align-items: center; gap: 10px;">
      <img src="../../logo_materre.png" alt="maTerre Logo" style="height: 50px; background: white; padding: 5px; border-radius: 50%;">
      <h1 style="margin: 0;">maTerre</h1>
    </div>
    <div style="display: flex; align-items: center; gap: 15px;">
      <button *ngIf="showInstallButton" (click)="installPwa()" 
              style="background: var(--mt-yellow); color: var(--mt-black); border: none; padding: 5px 10px; border-radius: 4px; font-weight: bold; cursor: pointer;">
        Installer l'App
      </button>

      <button *ngIf="!isLoggedIn" (click)="showLogin = true" 
              style="background: white; color: var(--mt-green); border: none; padding: 5px 15px; border-radius: 4px; font-weight: bold; cursor: pointer;">
        Se connecter
      </button>

      <button *ngIf="isLoggedIn" (click)="logout()" 
              style="background: rgba(255,255,255,0.2); color: white; border: 1px solid white; padding: 5px 15px; border-radius: 4px; cursor: pointer;">
        Déconnexion
      </button>
      
      <nav>
      <ul style="list-style: none; display: flex; gap: 1.5rem; margin: 0; padding: 0;">
        <li><a (click)="currentView = 'CATALOGUE'" style="color: white; text-decoration: none; cursor: pointer;" [style.border-bottom]="currentView === 'CATALOGUE' ? '2px solid var(--mt-yellow)' : 'none'">ACHETER</a></li>
        <li><a (click)="currentView = 'VERIFY'" style="color: white; text-decoration: none; cursor: pointer;" [style.border-bottom]="currentView === 'VERIFY' ? '2px solid var(--mt-yellow)' : 'none'">VÉRIFIER</a></li>
        <li *ngIf="isLoggedIn && userRole === 'NOTARY'"><a (click)="currentView = 'NOTARY'" style="color: white; text-decoration: none; cursor: pointer;" [style.border-bottom]="currentView === 'NOTARY' ? '2px solid var(--mt-yellow)' : 'none'">MISSIONS NOTAIRE</a></li>
        <li *ngIf="isLoggedIn && userRole === 'ADMIN'"><a (click)="currentView = 'ADMIN'" style="color: white; text-decoration: none; cursor: pointer;" [style.border-bottom]="currentView === 'ADMIN' ? '2px solid var(--mt-yellow)' : 'none'">ADMIN</a></li>
        <li *ngIf="isLoggedIn"><a (click)="currentView = 'PORTFOLIO'" style="color: white; text-decoration: none; cursor: pointer;" [style.border-bottom]="currentView === 'PORTFOLIO' ? '2px solid var(--mt-yellow)' : 'none'">MON PORTEFEUILLE</a></li>
        <li><a (click)="currentView = 'TITRE'" style="color: white; text-decoration: none; cursor: pointer;" [style.border-bottom]="currentView === 'TITRE' ? '2px solid var(--mt-yellow)' : 'none'">TITRER</a></li>
        <li><a (click)="currentView = 'PREINVEST'" style="color: white; text-decoration: none; cursor: pointer;" [style.border-bottom]="currentView === 'PREINVEST' ? '2px solid var(--mt-yellow)' : 'none'">PRÉ-INVESTIR</a></li>
        <li><a (click)="currentView = 'COINVEST'" style="color: white; text-decoration: none; cursor: pointer;" [style.border-bottom]="currentView === 'COINVEST' ? '2px solid var(--mt-yellow)' : 'none'">CO-INVESTIR</a></li>
        <li><a (click)="currentView = 'CLUB'" style="color: white; text-decoration: none; cursor: pointer; background: var(--mt-yellow); color: var(--mt-black); padding: 5px 10px; border-radius: 4px; font-weight: bold; margin-left: 10px;">CLUB ELITE</a></li>
      </ul>
    </nav>
    </div>
  </header>

  <main style="max-width: 1200px; margin: 2rem auto; padding: 0 1rem;">
    <!-- ADMIN VIEW -->
    <section *ngIf="currentView === 'ADMIN'">
      <app-admin-dashboard></app-admin-dashboard>
    </section>

    <!-- CLUB VIEW -->
    <section *ngIf="currentView === 'CLUB'">
      <app-subscription></app-subscription>
    </section>

    <!-- COINVEST VIEW -->
    <section *ngIf="currentView === 'COINVEST'">
      <app-investment-marketplace></app-investment-marketplace>
    </section>

    <!-- PREINVEST VIEW -->
    <section *ngIf="currentView === 'PREINVEST'">
      <app-pre-invest-dashboard></app-pre-invest-dashboard>
    </section>

    <!-- TITRE VIEW -->
    <section *ngIf="currentView === 'TITRE'">
      <app-titling-tracker></app-titling-tracker>
    </section>

    <!-- NOTARY VIEW -->
    <section *ngIf="currentView === 'NOTARY'">
      <app-notary-dashboard></app-notary-dashboard>
    </section>

    <!-- VERIFY VIEW -->
    <section *ngIf="currentView === 'VERIFY'" class="verify-section">
      <div class="card">
        <h2>L'Arbitrage Express en 48h</h2>
        <p>Entrez le numéro du titre foncier pour une vérification notariale instantanée.</p>
        
        <div style="display: flex; gap: 10px; margin-top: 2rem;">
          <input type="text" 
                 [(ngModel)]="titleNumber"
                 placeholder="Ex: Vol 123 Fol 45" 
                 style="flex: 1; padding: 12px; border: 1px solid #ccc; border-radius: 4px;">
          <button (click)="checkTitle()" 
                  [disabled]="isChecking || !titleNumber"
                  class="btn-primary">
            {{ isChecking ? 'Vérification en cours...' : 'Lancer le Check maTerre' }}
          </button>
        </div>

        <!-- Error Message -->
        <p *ngIf="errorMessage" style="color: var(--mt-red); margin-top: 1rem;">{{ errorMessage }}</p>

        <!-- Result Box -->
        <div *ngIf="verificationResult" 
             [style.border-left]="'10px solid ' + (verificationResult.status === 'RED' ? 'var(--mt-red)' : (verificationResult.status === 'GREEN' ? 'var(--mt-green)' : 'var(--mt-gold)'))"
             class="card" style="margin-top: 2rem; background: #fafafa;">
          <h3>Résultat de l'Arbitrage</h3>
          <p><strong>Titre :</strong> {{ verificationResult.title }}</p>
          <p [class.status-red]="verificationResult.status === 'RED'" 
             [class.status-green]="verificationResult.status === 'GREEN'"
             [class.status-yellow]="verificationResult.status === 'PENDING' || verificationResult.status === 'YELLOW'">
            {{ verificationResult.message }}
          </p>
          <div style="display: flex; justify-content: space-between; align-items: center; margin-top: 1.5rem;">
            <p style="margin: 0;"><small>Vérifié le : {{ verificationResult.date }}</small></p>
            <button *ngIf="verificationResult.status !== 'PENDING'" (click)="downloadPdf()" class="btn-primary" style="padding: 5px 15px; font-size: 0.8rem; background: var(--mt-gold); color: var(--mt-black);">
              📄 Télécharger PDF
            </button>
          </div>
        </div>

        <div style="margin-top: 2rem; border-top: 1px solid #eee; padding-top: 1rem;">
          <h3>Dernières vérifications :</h3>
          <div style="display: flex; gap: 20px; flex-wrap: wrap;">
            <div class="card" style="border-left: 5px solid var(--mt-green); flex: 1; min-width: 250px;">
              <p><strong>Titre:</strong> Vol 56 Fol 12</p>
              <p><strong>Status:</strong> <span class="status-green">VERT - SÛR</span></p>
            </div>
            <div class="card" style="border-left: 5px solid var(--mt-yellow); flex: 1; min-width: 250px;">
              <p><strong>Titre:</strong> Vol 89 Fol 04</p>
              <p><strong>Status:</strong> <span class="status-yellow">JAUNE - PRUDENCE</span></p>
            </div>
          </div>
        </div>
      </div>
    </section>

    <!-- CATALOGUE VIEW -->
    <section *ngIf="currentView === 'CATALOGUE'">
      <app-catalogue></app-catalogue>
    </section>
  </main>

  <footer style="text-align: center; padding: 2rem; background: var(--mt-grey); border-top: 2px solid var(--mt-gold);">
    <p>&copy; 2024 maTerre - L'Arbitre du Foncier au Cameroun. Tous droits réservés.</p>
  </footer>

  <!-- Login Overlay -->
  <div *ngIf="showLogin" class="modal-overlay">
    <div class="modal-content">
      <button (click)="showLogin = false" class="close-btn">&times;</button>
      <app-login (loginSuccess)="onLoginSuccess()"></app-login>
    </div>
  </div>
</div>
